     1→import React, { createContext, useCallback, useContext, useRef, useState } from "react";
     2→
     3→export type Tab =
     4→  | { id: "home"; type: "home"; title: string }
     5→  | { id: string; type: "session"; sessionId: string; title: string; initialSearch?: string; initialState?: unknown }
     6→  | { id: string; type: "branchLog"; localPath: string; branch: string; repoName: string | null; title: string }
     7→  | { id: string; type: "launcher"; cwd: string; command: string; title: string };
     8→
     9→type NavigateFn = (to: string | number) => void;
    10→
    11→interface TabsContextValue {
    12→  tabs: Tab[];
    13→  activeTabId: string;
    14→  homePathname: string;
    15→  openSessionTab: (sessionId: string, title: string, initialSearch?: string, initialState?: unknown) => void;
    16→  openBranchLogTab: (localPath: string, branch: string, repoName: string | null) => void;
    17→  openLauncherTab: (cwd: string, command: string, title: string) => void;
    18→  closeTab: (id: string) => void;
    19→  setActiveTab: (id: string) => void;
    20→  updateTabTitle: (id: string, title: string) => void;
    21→  /** Navigate the home tab (and activate it). Accepts a path string or -1 for back. */
    22→  navigateHome: (to: string | number) => void;
    23→  /** Called by HomeTabRoutes to register its navigate function. */
    24→  registerHomeNavigate: (fn: NavigateFn | null) => void;
    25→  /** Called by HomeTabRoutes when location changes, to keep homePathname in sync. */
    26→  updateHomePathname: (pathname: string) => void;
    27→  openSessionWindow: (sessionId: string) => void;
    28→  openBranchLogWindow: (localPath: string, branch: string, repoName: string | null) => void;
    29→}
    30→
    31→const TabsContext = createContext<TabsContextValue | null>(null);
    32→
    33→const HOME_TAB: Tab = { id: "home", type: "home", title: "Sessions" };
    34→
    35→export function parseInitialTab(tabParam: string | null): Tab | null {
    36→  if (!tabParam) return null;
    37→  if (tabParam.startsWith("session:")) {
    38→    const sessionId = tabParam.slice("session:".length);
    39→    return { id: tabParam, type: "session", sessionId, title: sessionId.slice(0, 8) + "…" };
    40→  }
    41→  if (tabParam.startsWith("branchLog:")) {
    42→    const qs = tabParam.slice("branchLog:".length);
    43→    const p = new URLSearchParams(qs);
    44→    const localPath = p.get("localPath") ?? "";
    45→    const branch = p.get("branch") ?? "";
    46→    const repoName = p.get("repoName") ?? null;
    47→    const title = repoName ? `${repoName}/${branch}` : branch;
    48→    return { id: tabParam, type: "branchLog", localPath, branch, repoName, title };
    49→  }
    50→  return null;
    51→}
    52→
    53→export function TabsProvider({
    54→  children,
    55→  initialTab,
    56→}: {
    57→  children: React.ReactNode;
    58→  initialTab?: Tab | null;
    59→}) {
    60→  const startTabs: Tab[] = initialTab ? [HOME_TAB, initialTab] : [HOME_TAB];
    61→  const startActiveId = initialTab ? initialTab.id : "home";
    62→
    63→  const [tabs, setTabs] = useState<Tab[]>(startTabs);
    64→  const [activeTabId, setActiveTabId] = useState<string>(startActiveId);
    65→  const [homePathname, setHomePathname] = useState("/");
    66→  const homeNavigateRef = useRef<NavigateFn | null>(null);
    67→
    68→  const openSessionTab = useCallback((sessionId: string, title: string, initialSearch?: string, initialState?: unknown) => {
    69→    const id = `session:${sessionId}`;
    70→    setTabs((prev) => {
    71→      if (prev.find((t) => t.id === id)) return prev;
    72→      return [...prev, { id, type: "session", sessionId, title, initialSearch, initialState }];
    73→    });
    74→    setActiveTabId(id);
    75→  }, []);
    76→
    77→  const openBranchLogTab = useCallback(
    78→    (localPath: string, branch: string, repoName: string | null) => {
    79→      const id = `branchLog:${localPath}:${branch}`;
    80→      setTabs((prev) => {
    81→        if (prev.find((t) => t.id === id)) return prev;
    82→        const title = repoName ? `${repoName}/${branch}` : branch;
    83→        return [...prev, { id, type: "branchLog", localPath, branch, repoName, title }];
    84→      });
    85→      setActiveTabId(id);
    86→    },
    87→    [],
    88→  );
    89→
    90→  const openLauncherTab = useCallback((cwd: string, command: string, title: string) => {
    91→    const id = `launcher:${Date.now()}`;
    92→    setTabs((prev) => [...prev, { id, type: "launcher", cwd, command, title }]);
    93→    setActiveTabId(id);
    94→  }, []);
    95→
    96→  const updateTabTitle = useCallback((id: string, title: string) => {
    97→    setTabs((prev) => prev.map((t) => (t.id === id ? { ...t, title } : t)));
    98→  }, []);
    99→
   100→  const closeTab = useCallback((id: string) => {
   101→    if (id === "home") return;
   102→    setTabs((prev) => {
   103→      const idx = prev.findIndex((t) => t.id === id);
   104→      const next = prev.filter((t) => t.id !== id);
   105→      setActiveTabId((current) => {
   106→        if (current !== id) return current;
   107→        if (next.length === 0) return "home";
   108→        return next[Math.max(0, idx - 1)].id;
   109→      });
   110→      return next;
   111→    });
   112→  }, []);
   113→
   114→  const navigateHome = useCallback((to: string | number) => {
   115→    setActiveTabId("home");
   116→    homeNavigateRef.current?.(to);
   117→    if (typeof to === "string") setHomePathname(to.split("?")[0]);
   118→  }, []);
   119→
   120→  const registerHomeNavigate = useCallback((fn: NavigateFn | null) => {
   121→    homeNavigateRef.current = fn;
   122→  }, []);
   123→
   124→  const updateHomePathname = useCallback((pathname: string) => {
   125→    setHomePathname(pathname);
   126→  }, []);
   127→
   128→  const openSessionWindow = useCallback((sessionId: string) => {
   129→    // eslint-disable-next-line @typescript-eslint/no-explicit-any
   130→    (window as any).electronAPI?.openWindow(`session:${sessionId}`);
   131→  }, []);
   132→
   133→  const openBranchLogWindow = useCallback(
   134→    (localPath: string, branch: string, repoName: string | null) => {
   135→      const params = new URLSearchParams({ localPath, branch, ...(repoName ? { repoName } : {}) });
   136→      // eslint-disable-next-line @typescript-eslint/no-explicit-any
   137→      (window as any).electronAPI?.openWindow(`branchLog:${params.toString()}`);
   138→    },
   139→    [],
   140→  );
   141→
   142→  return (
   143→    <TabsContext.Provider
   144→      value={{
   145→        tabs,
   146→        activeTabId,
   147→        homePathname,
   148→        openSessionTab,
   149→        openBranchLogTab,
   150→        openLauncherTab,
   151→        closeTab,
   152→        setActiveTab: setActiveTabId,
   153→        updateTabTitle,
   154→        navigateHome,
   155→        registerHomeNavigate,
   156→        updateHomePathname,
   157→        openSessionWindow,
   158→        openBranchLogWindow,
   159→      }}
   160→    >
   161→      {children}
   162→    </TabsContext.Provider>
   163→  );
   164→}
   165→
   166→export function useTabs(): TabsContextValue {
   167→  const ctx = useContext(TabsContext);
   168→  if (!ctx) throw new Error("useTabs must be used within TabsProvider");
   169→  return ctx;
   170→}
