     1→import React, { useEffect, useState, useCallback } from "react";
     2→import { Center, Loader, Alert, Text, Table, Box, SegmentedControl, Group, Anchor, Button, Modal, Textarea, Select, Switch, Tooltip } from "@mantine/core";
     3→import { fetchSessions, fetchRepoStatuses, subscribeToUpdates, archiveSession, unarchiveSession, syncSessions, type Session, type RepoStatus } from "../api";
     4→import { SessionRow, COL_WIDTHS } from "../components/SessionRow";
     5→import { useBreadcrumb } from "../BreadcrumbContext";
     6→import { useTabs } from "../TabsContext";
     7→
     8→const SESSION_COLUMNS: { label: string; width: number }[] = [
     9→  { label: "Session ID",  width: COL_WIDTHS.sessionId      },
    10→  { label: "User",        width: COL_WIDTHS.user            },
    11→  { label: "Repo",        width: COL_WIDTHS.repo            },
    12→  { label: "Branch",      width: COL_WIDTHS.branch          },
    13→  { label: "Intent",      width: COL_WIDTHS.intent          },
    14→  { label: "Parent",      width: COL_WIDTHS.parentSessionId },
    15→  { label: "Started",     width: COL_WIDTHS.started         },
    16→  { label: "Updated",     width: COL_WIDTHS.updated         },
    17→  { label: "",            width: COL_WIDTHS.actions         },
    18→];
    19→
    20→const REPO_COLUMNS = ["Repo", "User", "Branch"] as const;
    21→
    22→const SESSION_TOTAL_WIDTH = Object.values(COL_WIDTHS).reduce((a, b) => a + b, 0) + 16;
    23→
    24→export function ActiveSessions() {
    25→  const { openSessionTab, openBranchLogTab, openLauncherTab } = useTabs();
    26→  const [view, setView] = useState<"sessions" | "repos">("sessions");
    27→  const [sessions, setSessions] = useState<Session[]>([]);
    28→  const [repoStatuses, setRepoStatuses] = useState<RepoStatus[]>([]);
    29→  const [loading, setLoading] = useState(true);
    30→  const [error, setError] = useState<string | null>(null);
    31→  const { setCrumbs } = useBreadcrumb();
    32→
    33→  const [newSessionOpen, setNewSessionOpen] = useState(false);
    34→  const [newPrompt, setNewPrompt] = useState("");
    35→  const [newCwd, setNewCwd] = useState("");
    36→  const [showArchived, setShowArchived] = useState(false);
    37→  const [syncing, setSyncing] = useState(false);
    38→  const [archivedIds, setArchivedIds] = useState<Set<string>>(new Set());
    39→
    40→  const load = useCallback(async (archived = false) => {
    41→    try {
    42→      const [data, archivedData, statuses] = await Promise.all([
    43→        fetchSessions(false),
    44→        fetchSessions(true),
    45→        fetchRepoStatuses(),
    46→      ]);
    47→      setSessions(archived ? archivedData : data);
    48→      setArchivedIds(new Set(archivedData.map((s) => s.sessionId)));
    49→      setRepoStatuses(statuses);
    50→      setError(null);
    51→      return data;
    52→    } catch (err) {
    53→      setError(String(err));
    54→      return [] as Session[];
    55→    }
    56→  }, []);
    57→
    58→  useEffect(() => {
    59→    load(showArchived).then((data) => {
    60→      const first = data[0];
    61→      const user = first?.gitUserName ?? first?.gitUserEmail ?? null;
    62→      setCrumbs([
    63→        ...(user ? [{ label: user }] : []),
    64→      ]);
    65→    }).finally(() => setLoading(false));
    66→    return subscribeToUpdates(() => { load(showArchived).catch(() => undefined); });
    67→  }, [load, showArchived]);
    68→
    69→  async function handleArchive(sessionId: string) {
    70→    const isCurrentlyArchived = archivedIds.has(sessionId);
    71→    try {
    72→      if (isCurrentlyArchived) {
    73→        await unarchiveSession(sessionId);
    74→      } else {
    75→        await archiveSession(sessionId);
    76→      }
    77→      await load(showArchived);
    78→    } catch { /* ignore */ }
    79→  }
    80→
    81→  async function handleSync() {
    82→    setSyncing(true);
    83→    try {
    84→      await syncSessions();
    85→      await load(showArchived);
    86→    } catch { /* ignore */ } finally {
    87→      setSyncing(false);
    88→    }
    89→  }
    90→
    91→  function handleSpawn() {
    92→    const prompt = newPrompt.trim();
    93→    if (!prompt) return;
    94→    const cwd = newCwd || (repoStatuses[0]?.localPath ?? process.env.HOME ?? "/");
    95→    const escaped = prompt.replace(/'/g, "'\\''");
    96→    setNewSessionOpen(false);
    97→    setNewPrompt("");
    98→    openLauncherTab(cwd, `claude '${escaped}'`, `claude: ${prompt.slice(0, 40)}${prompt.length > 40 ? "…" : ""}`);
    99→  }
   100→
   101→  if (loading) {
   102→    return <Center style={{ flex: 1 }}><Loader size="md" color="indigo" /></Center>;
   103→  }
   104→
   105→  if (error) {
   106→    return (
   107→      <Center style={{ flex: 1, padding: 24 }}>
   108→        <Alert color="red" title="Cannot reach API server" maw={480}>
   109→          <Text size="sm" mb={4}>
   110→            Start the server with:{" "}
   111→            <Text component="span" ff="monospace" size="sm">claude-hook-handler serve</Text>
   112→          </Text>
   113→          <Text size="xs" c="dimmed">{error}</Text>
   114→        </Alert>
   115→      </Center>
   116→    );
   117→  }
   118→
   119→  const cwdOptions = repoStatuses.map((r) => ({ value: r.localPath, label: r.name ?? r.localPath }));
   120→
   121→  return (
   122→    <Box style={{ flex: 1, overflow: "hidden", display: "flex", flexDirection: "column" }}>
   123→      <Modal
   124→        opened={newSessionOpen}
   125→        onClose={() => setNewSessionOpen(false)}
   126→        title="New session"
   127→        size="md"
   128→      >
   129→        {cwdOptions.length > 0 && (
   130→          <Select
   131→            label="Working directory"
   132→            placeholder="Pick a repo…"
   133→            data={cwdOptions}
   134→            value={newCwd || null}
   135→            onChange={(v) => setNewCwd(v ?? "")}
   136→            mb="sm"
   137→            clearable
   138→          />
   139→        )}
   140→        <Textarea
   141→          label="Prompt"
   142→          placeholder="What should Claude do?"
   143→          autosize
   144→          minRows={4}
   145→          maxRows={12}
   146→          value={newPrompt}
   147→          onChange={(e) => setNewPrompt(e.currentTarget.value)}
   148→          onKeyDown={(e) => { if (e.key === "Enter" && (e.metaKey || e.ctrlKey)) handleSpawn(); }}
   149→          mb="sm"
   150→          data-autofocus
   151→        />
   152→        <Group justify="flex-end">
   153→          <Button variant="default" size="xs" onClick={() => setNewSessionOpen(false)}>Cancel</Button>
   154→          <Button size="xs" color="indigo" disabled={!newPrompt.trim()} onClick={handleSpawn}>
   155→            Start session
   156→          </Button>
   157→        </Group>
   158→      </Modal>
   159→
   160→      <Group px={12} py={8} justify="space-between" style={{ borderBottom: "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))", flexShrink: 0 }}>
   161→        <Group gap={8}>
   162→          <SegmentedControl
   163→            size="xs"
   164→            value={view}
   165→            onChange={(v) => setView(v as "sessions" | "repos")}
   166→            data={[
   167→              { label: "Sessions", value: "sessions" },
   168→              { label: "Repos",    value: "repos"    },
   169→            ]}
   170→          />
   171→          {view === "sessions" && (
   172→            <Switch
   173→              size="xs"
   174→              label="Archived"
   175→              checked={showArchived}
   176→              onChange={(e) => setShowArchived(e.currentTarget.checked)}
   177→            />
   178→          )}
   179→        </Group>
   180→        <Group gap={8}>
   181→          {view === "sessions" && (
   182→            <Tooltip label="Sync active sessions" withArrow>
   183→              <Button size="xs" variant="default" loading={syncing} onClick={handleSync}>
   184→                Sync
   185→              </Button>
   186→            </Tooltip>
   187→          )}
   188→          <Button size="xs" color="indigo" onClick={() => setNewSessionOpen(true)}>
   189→            New session
   190→          </Button>
   191→        </Group>
   192→      </Group>
   193→
   194→      {view === "sessions" ? (
   195→        sessions.length === 0 ? (
   196→          <Center style={{ flex: 1 }}><Text c="dimmed" size="sm">No sessions yet.</Text></Center>
   197→        ) : (
   198→          <Box style={{ flex: 1, overflow: "hidden" }}>
   199→            <Table.ScrollContainer minWidth={SESSION_TOTAL_WIDTH} h="100%">
   200→              <Table stickyHeader highlightOnHover>
   201→                <Table.Thead>
   202→                  <Table.Tr>
   203→                    {SESSION_COLUMNS.map(({ label, width }) => (
   204→                      <Table.Th key={label} style={{ width, fontSize: 12, textTransform: "uppercase", letterSpacing: 0.5 }}>
   205→                        {label}
   206→                      </Table.Th>
   207→                    ))}
   208→                  </Table.Tr>
   209→                </Table.Thead>
   210→                <Table.Tbody>
   211→                  {sessions.map((item) => (
   212→                    <SessionRow
   213→                      key={item.sessionId}
   214→                      session={item}
   215→                      onPress={() =>
   216→                        openSessionTab(
   217→                          item.sessionId,
   218→                          item.summary ?? item.intent ?? item.sessionId.slice(0, 8) + "…",
   219→                        )
   220→                      }
   221→                      onArchive={handleArchive}
   222→                      isArchived={archivedIds.has(item.sessionId)}
   223→                    />
   224→                  ))}
   225→                </Table.Tbody>
   226→              </Table>
   227→            </Table.ScrollContainer>
   228→          </Box>
   229→        )
   230→      ) : (
   231→        repoStatuses.length === 0 ? (
   232→          <Center style={{ flex: 1 }}><Text c="dimmed" size="sm">No repos configured.</Text></Center>
   233→        ) : (
   234→          <Box style={{ flex: 1, overflow: "hidden" }}>
   235→            <Table.ScrollContainer minWidth={600} h="100%">
   236→              <Table stickyHeader highlightOnHover>
   237→                <Table.Thead>
   238→                  <Table.Tr>
   239→                    {REPO_COLUMNS.map((label) => (
   240→                      <Table.Th key={label} style={{ fontSize: 12, textTransform: "uppercase", letterSpacing: 0.5 }}>
   241→                        {label}
   242→                      </Table.Th>
   243→                    ))}
   244→                  </Table.Tr>
   245→                </Table.Thead>
   246→                <Table.Tbody>
   247→                  {repoStatuses.map((repo) => (
   248→                    <Table.Tr key={repo.localPath}>
   249→                      <Table.Td>
   250→                        {repo.currentBranch ? (
   251→                          <Anchor
   252→                            size="sm"
   253→                            fw={500}
   254→                            onClick={() =>
   255→                              openBranchLogTab(repo.localPath, repo.currentBranch!, repo.name)
   256→                            }
   257→                            style={{ cursor: "pointer" }}
   258→                            underline="never"
   259→                          >
   260→                            {repo.name}
   261→                          </Anchor>
   262→                        ) : (
   263→                          <Text size="sm" fw={500}>{repo.name}</Text>
   264→                        )}
   265→                      </Table.Td>
   266→                      <Table.Td>
   267→                        <Text size="sm" c="dimmed">{repo.gitUserName ?? repo.gitUserEmail ?? "—"}</Text>
   268→                      </Table.Td>
   269→                      <Table.Td>
   270→                        <Text size="sm" ff="monospace" c={repo.currentBranch ? "teal" : "dimmed"}>
   271→                          {repo.currentBranch ?? "—"}
   272→                        </Text>
   273→                      </Table.Td>
   274→                    </Table.Tr>
   275→                  ))}
   276→                </Table.Tbody>
   277→              </Table>
   278→            </Table.ScrollContainer>
   279→          </Box>
   280→        )
   281→      )}
   282→    </Box>
   283→  );
   284→}
