     1→import { app, BrowserWindow, ipcMain } from "electron";
     2→import { join } from "path";
     3→
     4→function createWindow(tabParam?: string): void {
     5→  const win = new BrowserWindow({
     6→    width: 1400,
     7→    height: 900,
     8→    webPreferences: {
     9→      preload: join(__dirname, "../preload/index.js"),
    10→      contextIsolation: true,
    11→      nodeIntegration: false,
    12→    },
    13→  });
    14→
    15→  const tabQuery = tabParam ? `?tab=${encodeURIComponent(tabParam)}` : "";
    16→
    17→  if (process.env.ELECTRON_RENDERER_URL) {
    18→    win.loadURL(`${process.env.ELECTRON_RENDERER_URL}${tabQuery}`);
    19→    win.webContents.openDevTools();
    20→  } else {
    21→    win.loadFile(join(__dirname, "../renderer/index.html"), {
    22→      query: tabParam ? { tab: tabParam } : undefined,
    23→    });
    24→  }
    25→}
    26→
    27→app.whenReady().then(() => {
    28→  ipcMain.handle("open-window", (_event, tabParam: string) => {
    29→    createWindow(tabParam);
    30→  });
    31→
    32→  createWindow();
    33→});
    34→
    35→app.on("window-all-closed", () => {
    36→  if (process.platform !== "darwin") app.quit();
    37→});
    38→
    39→app.on("activate", () => {
    40→  if (BrowserWindow.getAllWindows().length === 0) createWindow();
    41→});
