    41→function getActiveNav(pathname: string): string {
    42→  if (pathname === "/" || pathname.startsWith("/sessions/")) return "/";
    43→  if (pathname === "/session-tree") return "/session-tree";
    44→  if (pathname === "/checkpoints/timeline") return "/checkpoints/timeline";
    45→  if (pathname.startsWith("/checkpoints")) return "/checkpoints";
