    53→
    54→function BranchSelector({
    55→  localPath,
    56→  branch,
    57→  repoName,
    58→  onBranchChange,
    59→}: {
    60→  localPath: string;
    61→  branch: string;
    62→  repoName: string | null;
    63→  onBranchChange: (branch: string) => void;
    64→}) {
    65→  const [branches, setBranches] = useState<string[]>([]);
    66→  const [loading, setLoading] = useState(true);
    67→
    68→  useEffect(() => {
    69→    setLoading(true);
    70→    fetchBranches(localPath)
    71→      .then(setBranches)
    72→      .catch(() => setBranches(branch ? [branch] : []))
    73→      .finally(() => setLoading(false));
    74→  }, [localPath]);
    75→
    76→  return (
    77→    <Select
    78→      size="xs"
    79→      value={branch}
    80→      data={branches}
