   175→function TabContent({ tab }: { tab: Tab }) {
   176→  if (tab.type === "session") return <SessionTab sessionId={tab.sessionId} initialSearch={tab.initialSearch} initialState={tab.initialState} />;
   177→  if (tab.type === "branchLog") {
