     1→import React, { useState } from "react";
     2→import { Table, Text, Anchor, ActionIcon, Tooltip, Badge } from "@mantine/core";
     3→import type { Session } from "../api";
     4→import { relativeTime, absoluteTime } from "./TimeAgo";
     5→
     6→interface Props {
     7→  session: Session;
     8→  onPress: () => void;
     9→  onArchive?: (sessionId: string) => void;
    10→  isArchived?: boolean;
    11→}
    12→
    13→export const COL_WIDTHS = {
    14→  sessionId:       180,
    15→  user:            160,
    16→  repo:            130,
    17→  branch:          120,
    18→  intent:          340,
    19→  parentSessionId: 120,
    20→  started:         110,
    21→  updated:         110,
    22→  actions:          56,
    23→} as const;
    24→
    25→
    26→
    27→function activityDot(updatedAt: string): { color: string; label: string } {
    28→  const diff = Date.now() - new Date(updatedAt).getTime();
    29→  if (diff < 2 * 60 * 1000)  return { color: "var(--mantine-color-green-6)", label: "Active" };
    30→  if (diff < 15 * 60 * 1000) return { color: "var(--mantine-color-yellow-6)", label: "Idle" };
    31→  return { color: "light-dark(var(--mantine-color-gray-4), var(--mantine-color-dark-3))", label: "Inactive" };
    32→}
    33→
    34→interface CopyCellProps {
    35→  copyValue: string;
    36→  width: number;
    37→  children: React.ReactNode;
    38→  prefix?: React.ReactNode;
    39→}
    40→
    41→function CopyCell({ copyValue, width, children, prefix }: CopyCellProps) {
    42→  const [hovered, setHovered] = useState(false);
    43→  const [copied, setCopied] = useState(false);
    44→
    45→  function copy(e: React.MouseEvent) {
    46→    e.stopPropagation();
    47→    navigator.clipboard.writeText(copyValue).catch(() => undefined);
    48→    setCopied(true);
    49→    setTimeout(() => setCopied(false), 1200);
    50→  }
    51→
    52→  return (
    53→    <Table.Td
    54→      onMouseEnter={() => setHovered(true)}
    55→      onMouseLeave={() => { setHovered(false); setCopied(false); }}
    56→      style={{ width, maxWidth: width, overflow: "hidden", position: "relative", paddingRight: hovered ? 28 : undefined }}
    57→    >
    58→      <div style={{ display: "flex", alignItems: "center", gap: 6, overflow: "hidden" }}>
    59→        {prefix}
    60→        <div style={{ overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", flex: 1 }}>
    61→          {children}
    62→        </div>
    63→      </div>
    64→      {hovered && copyValue && (
    65→        <Tooltip label={copied ? "Copied!" : "Copy"} withArrow position="top" openDelay={0}>
    66→          <ActionIcon
    67→            size="xs"
    68→            variant="subtle"
    69→            color={copied ? "green" : "gray"}
    70→            onClick={copy}
    71→            style={{ position: "absolute", right: 4, top: "50%", transform: "translateY(-50%)" }}
    72→          >
    73→            {copied ? "✓" : "⧉"}
    74→          </ActionIcon>
    75→        </Tooltip>
    76→      )}
    77→    </Table.Td>
    78→  );
    79→}
    80→
    81→export function SessionRow({ session, onPress, onArchive, isArchived }: Props) {
    82→  const dot = activityDot(session.updatedAt);
    83→  const intent = session.intent ?? session.summary ?? session.prompt?.slice(0, 160) ?? "—";
    84→  const shortId = session.sessionId.slice(0, 8) + "…";
    85→  const shortParent = session.parentSessionId ? session.parentSessionId.slice(0, 8) + "…" : null;
    86→  const [archiving, setArchiving] = useState(false);
    87→
    88→  return (
    89→    <>
    90→      <Table.Tr onClick={onPress} style={{ cursor: "pointer" }}>
    91→        <CopyCell
    92→          copyValue={session.sessionId}
    93→          width={COL_WIDTHS.sessionId}
    94→          prefix={
    95→            <Tooltip label={dot.label} withArrow position="left" openDelay={300}>
    96→              <div style={{ width: 8, height: 8, borderRadius: "50%", backgroundColor: dot.color, flexShrink: 0 }} />
    97→            </Tooltip>
    98→          }
    99→        >
   100→          <div style={{ display: "flex", alignItems: "center", gap: 6, overflow: "hidden" }}>
   101→            <Text ff="monospace" size="sm" c="indigo" style={{ flexShrink: 0 }}>
   102→              {shortId}
   103→            </Text>
   104→            {session.isLive && (
   105→              <Badge size="xs" color="orange" variant="light" style={{ flexShrink: 0 }}>
   106→                live
   107→              </Badge>
   108→            )}
   109→          </div>
   110→        </CopyCell>
   111→
   112→        <CopyCell copyValue={session.gitUserEmail ?? session.gitUserName ?? ""} width={COL_WIDTHS.user}>
   113→          {session.gitUserEmail ? (
   114→            <Anchor
   115→              size="sm"
   116→              href={`mailto:${session.gitUserEmail}`}
   117→              onClick={(e) => e.stopPropagation()}
   118→            >
   119→              {session.gitUserName ?? session.gitUserEmail}
   120→            </Anchor>
   121→          ) : (
   122→            <Text size="sm" c={session.gitUserName ? undefined : "dimmed"}>
   123→              {session.gitUserName ?? "—"}
   124→            </Text>
   125→          )}
   126→        </CopyCell>
   127→
   128→        <CopyCell copyValue={session.repoName ?? ""} width={COL_WIDTHS.repo}>
   129→          <Text size="sm" c={session.repoName ? undefined : "dimmed"}>
   130→            {session.repoName ?? "—"}
   131→          </Text>
   132→        </CopyCell>
   133→
   134→        <CopyCell copyValue={session.branch ?? ""} width={COL_WIDTHS.branch}>
   135→          <Text size="sm" ff="monospace" c={session.branch ? "teal" : "dimmed"}>
   136→            {session.branch ?? "—"}
   137→          </Text>
   138→        </CopyCell>
   139→
   140→        <CopyCell copyValue={intent} width={COL_WIDTHS.intent}>
   141→          <Text size="sm">{intent}</Text>
   142→        </CopyCell>
   143→
   144→        <CopyCell copyValue={session.parentSessionId ?? ""} width={COL_WIDTHS.parentSessionId}>
   145→          {shortParent ? (
   146→            <Text ff="monospace" size="sm" c="blue">{shortParent}</Text>
   147→          ) : (
   148→            <Text size="sm" c="dimmed">—</Text>
   149→          )}
   150→        </CopyCell>
   151→
   152→        <CopyCell copyValue={absoluteTime(session.startedAt)} width={COL_WIDTHS.started}>
   153→          <Text size="sm" c="dimmed">{relativeTime(session.startedAt)}</Text>
   154→        </CopyCell>
   155→
   156→        <CopyCell copyValue={absoluteTime(session.updatedAt)} width={COL_WIDTHS.updated}>
   157→          <Text size="sm" c="dimmed">{relativeTime(session.updatedAt)}</Text>
   158→        </CopyCell>
   159→
   160→        <Table.Td style={{ width: COL_WIDTHS.actions }} onClick={(e) => e.stopPropagation()}>
   161→          {onArchive && (
   162→            <Tooltip label={isArchived ? "Unarchive" : "Archive"} withArrow position="left" openDelay={300}>
   163→              <ActionIcon
   164→                size="sm"
   165→                variant="subtle"
   166→                color={isArchived ? "blue" : "gray"}
   167→                loading={archiving}
   168→                onClick={async (e) => {
   169→                  e.stopPropagation();
   170→                  setArchiving(true);
   171→                  try { await onArchive(session.sessionId); }
   172→                  finally { setArchiving(false); }
   173→                }}
   174→              >
   175→                {isArchived ? "↩" : "⊗"}
   176→              </ActionIcon>
   177→            </Tooltip>
   178→          )}
   179→        </Table.Td>
   180→      </Table.Tr>
   181→    </>
   182→  );
   183→}
