     1→import React from "react";
     2→import { Box, Text, ActionIcon, UnstyledButton, Tooltip } from "@mantine/core";
     3→import { useTabs, type Tab } from "../TabsContext";
     4→
     5→function tabIcon(tab: Tab): string {
     6→  if (tab.type === "home") return "≡";
     7→  if (tab.type === "session") return "◎";
     8→  if (tab.type === "branchLog") return "⬡";
     9→  return "·";
    10→}
    11→
    12→export function TabBar() {
    13→  const { tabs, activeTabId, setActiveTab, closeTab, openSessionWindow, openBranchLogWindow } =
    14→    useTabs();
    15→
    16→  if (tabs.length <= 1) return null;
    17→
    18→  return (
    19→    <Box
    20→      style={{
    21→        display: "flex",
    22→        flexDirection: "row",
    23→        borderBottom:
    24→          "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
    25→        backgroundColor:
    26→          "light-dark(var(--mantine-color-gray-0), var(--mantine-color-dark-8))",
    27→        overflowX: "auto",
    28→        flexShrink: 0,
    29→        minHeight: 32,
    30→      }}
    31→    >
    32→      {tabs.map((tab) => (
    33→        <TabItem
    34→          key={tab.id}
    35→          tab={tab}
    36→          isActive={tab.id === activeTabId}
    37→          onActivate={() => setActiveTab(tab.id)}
    38→          onClose={tab.id !== "home" ? () => closeTab(tab.id) : undefined}
    39→          onPopOut={
    40→            tab.type === "session"
    41→              ? () => {
    42→                  openSessionWindow(tab.sessionId);
    43→                  closeTab(tab.id);
    44→                }
    45→              : tab.type === "branchLog"
    46→                ? () => {
    47→                    openBranchLogWindow(tab.localPath, tab.branch, tab.repoName);
    48→                    closeTab(tab.id);
    49→                  }
    50→                : undefined
    51→          }
    52→        />
    53→      ))}
    54→    </Box>
    55→  );
    56→}
    57→
    58→function TabItem({
    59→  tab,
    60→  isActive,
    61→  onActivate,
    62→  onClose,
    63→  onPopOut,
    64→}: {
    65→  tab: Tab;
    66→  isActive: boolean;
    67→  onActivate: () => void;
    68→  onClose?: () => void;
    69→  onPopOut?: () => void;
    70→}) {
    71→  // eslint-disable-next-line @typescript-eslint/no-explicit-any
    72→  const hasElectron = !!(window as any).electronAPI;
    73→
    74→  return (
    75→    <UnstyledButton
    76→      onClick={onActivate}
    77→      style={{
    78→        display: "flex",
    79→        alignItems: "center",
    80→        gap: 4,
    81→        paddingLeft: 10,
    82→        paddingRight: 4,
    83→        paddingTop: 0,
    84→        paddingBottom: 0,
    85→        borderRight:
    86→          "1px solid light-dark(var(--mantine-color-gray-3), var(--mantine-color-dark-4))",
    87→        backgroundColor: isActive
    88→          ? "light-dark(var(--mantine-color-white), var(--mantine-color-dark-6))"
    89→          : "transparent",
    90→        borderBottom: isActive
    91→          ? "2px solid var(--mantine-color-indigo-6)"
    92→          : "2px solid transparent",
    93→        cursor: "pointer",
    94→        flexShrink: 0,
    95→        maxWidth: 240,
    96→        minHeight: 32,
    97→      }}
    98→    >
    99→      <Text size="xs" c="dimmed" style={{ fontFamily: "monospace", flexShrink: 0 }}>
   100→        {tabIcon(tab)}
   101→      </Text>
   102→      <Text
   103→        size="xs"
   104→        style={{
   105→          maxWidth: 150,
   106→          overflow: "hidden",
   107→          textOverflow: "ellipsis",
   108→          whiteSpace: "nowrap",
   109→          flex: 1,
   110→        }}
   111→      >
   112→        {tab.title}
   113→      </Text>
   114→      {onPopOut && hasElectron && (
   115→        <Tooltip label="Pop out to window" withArrow position="top" openDelay={400}>
   116→          <ActionIcon
   117→            size="xs"
   118→            variant="subtle"
   119→            color="gray"
   120→            onClick={(e) => {
   121→              e.stopPropagation();
   122→              onPopOut();
   123→            }}
   124→            style={{ flexShrink: 0 }}
   125→          >
   126→            ⊡
   127→          </ActionIcon>
   128→        </Tooltip>
   129→      )}
   130→      {onClose && (
   131→        <ActionIcon
   132→          size="xs"
   133→          variant="subtle"
   134→          color="gray"
   135→          onClick={(e) => {
   136→            e.stopPropagation();
   137→            onClose();
   138→          }}
   139→          style={{ flexShrink: 0 }}
   140→        >
   141→          ×
   142→        </ActionIcon>
   143→      )}
   144→    </UnstyledButton>
   145→  );
   146→}
