   403→export function subscribeToUpdates(onUpdate: () => void): () => void {
   404→  let ws: WebSocket | null = null;
   405→  let timer: ReturnType<typeof setTimeout> | null = null;
   406→  let closed = false;
   407→  let delay = 1000;
   408→
   409→  function connect() {
   410→    if (closed) return;
   411→    ws = new WebSocket(WS_URL);
   412→
   413→    ws.onopen = () => {
   414→      delay = 1000; // reset backoff on successful connection
   415→    };
   416→
   417→    ws.onmessage = (e) => {
   418→      try {
   419→        const msg = JSON.parse(e.data as string) as { type: string };
   420→        if (msg.type === "sessions_updated") onUpdate();
   421→      } catch {
   422→        // ignore malformed messages
   423→      }
   424→    };
   425→
   426→    ws.onclose = () => {
   427→      if (closed) return;
   428→      timer = setTimeout(() => {
   429→        delay = Math.min(delay * 2, 30000);
   430→        connect();
   431→      }, delay);
   432→    };
