import React, { createContext, useCallback, useContext, useEffect, useRef, useState } from "react";

const TABS_KEY = "gossamer-tabs";
const ACTIVE_TAB_KEY = "gossamer-active-tab";

function loadPersistedState(): { tabs: Tab[]; activeTabId: string } | null {
  try {
    const raw = localStorage.getItem(TABS_KEY);
    if (!raw) return null;
    const tabs = JSON.parse(raw) as Tab[];
    const activeTabId = localStorage.getItem(ACTIVE_TAB_KEY) ?? "home";
    return { tabs, activeTabId };
  } catch {
    return null;
  }
}

function persistState(tabs: Tab[], activeTabId: string): void {
  // Don't persist launcher tabs — they represent ephemeral running processes
  const toSave = tabs.filter((t) => t.type !== "launcher");
  localStorage.setItem(TABS_KEY, JSON.stringify(toSave));
  localStorage.setItem(ACTIVE_TAB_KEY, activeTabId);
}
